    10→    if (!session?.user) {
    11→        return NextResponse.json({ error: 'غير مصرح' }, { status: 401 });
    12→    }
    13→
    14→    const currentUser = await getCurrentUser(session);
    15→
    16→    if (!currentUser) {
    17→        return NextResponse.json({ error: 'غير مصرح' }, { status: 403 });
    18→    }
    19→
    20→    try {
    21→        const { searchParams } = new URL(req.url);
    22→        const courseId = searchParams.get('courseId');
    23→        const studentId = searchParams.get('studentId');
    24→        const status = searchParams.get('status');
    25→
    26→        let query = supabaseAdmin
    27→            .from('enrollments')
    28→            .select(`
    29→                *,
    30→                student:users!enrollments_student_id_fkey(id, name, email, image),
    31→                course:courses(id, title, slug, image_url, teacher_id)
    32→            `)
