    43→            query = query.eq('student_id', studentId);
    44→        }
    45→
    46→        if (status) {
    47→            query = query.eq('status', status);
    48→        }
    49→
    50→        const { data: enrollments, error } = await query;
    51→
    52→        if (error) {
    53→            console.error('Error fetching enrollments:', error);
    54→            return NextResponse.json({ error: 'فشل جلب التسجيلات' }, { status: 500 });
